// Validate CBAM certificate hash integrity
// Triggered when hash collision detected or hash generation fails
const alert = $input.first().json;

// Expected payload:
// { installationId, reportingPeriod, expectedHash, actualHash, timestamp, severity }

const result = {
  type: 'certificate_hash_collision',
  severity: alert.severity || 'P0',
  installationId: alert.installationId || 'UNKNOWN',
  reportingPeriod: alert.reportingPeriod || 'UNKNOWN',
  expectedHash: alert.expectedHash || '',
  actualHash: alert.actualHash || '',
  timestamp: alert.timestamp || new Date().toISOString(),
  action: 'AUTO_DISABLE_SIGNING',
  message: `Certificate hash collision detected for installation ${alert.installationId}. Expected: ${alert.expectedHash?.slice(0, 16)}, Actual: ${alert.actualHash?.slice(0, 16)}. Auto-disabling certificate signing.`,
};

// P0 severity check
if (result.severity === 'P0') {
  result.pagerDutyRequired = true;
  result.autoDisableSigning = true;
}

console.log(`[W20] 🔴 Certificate hash collision: ${result.message}`);

return [{ json: result }];

